const url = "https://sicte.herokuapp.com/api/login";

axios.interceptors.request.use(
    config => {
        config.headers.authorization = 'Bearer ${accessToken}';
        console.log(config.headers.authorization)
        return config;
    },
    error => {
        return Promise.reject(error);
    }
